  const confirmAndSavePurchase = (finalItems: PurchaseItem[]) => {
     const finalTotal = finalItems.reduce((sum, item) => sum + item.buyPrice * item.quantity, 0);
     const purchaseRecord: PurchaseRecord = {
      id: `purchase-${Date.now()}`,
