                    onChange={(e) => setSupplierSearchTerm(e.target.value)}
                    placeholder="Tedarikçi ara..."
                    className="w-full h-12 border-2 border-slate-300 rounded-lg px-4 text-lg focus:outline-none focus:ring-2 focus:ring-cyan-500 mb-4"
                    autoFocus
                />
                <div className="max-h-80 overflow-y-auto space-y-2">
                    {filteredSuppliers.map(s => (
                        <button
                            key={s.id}
