          .btn-action {
              display: flex; align-items: center; justify-content: center; gap: 0.5rem; height: 3.5rem; padding: 0 1rem;
              border-radius: 0.5rem; font-weight: 600; transition: all 0.2s; white-space: nowrap;
              border: 2px solid transparent;
          }
      `}</style>
      <div className="flex-grow flex flex-col bg-white border border-slate-200/80 rounded-lg shadow-lg overflow-hidden">
        <header className="p-4 border-b border-slate-200 flex-shrink-0 bg-slate-50/50">
           <div className="flex justify-between items-center mb-4">
             <h2 className="text-2xl font-bold text-slate-800">Alış Faturası Oluştur</h2>
             <div>
                <span className="font-semibold text-slate-600">Tedarikçi: </span>
