              </form>
              <div className="relative flex-grow" ref={searchContainerRef}>
                  <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} onKeyDown={handleSearchKeyDown} placeholder="Ürün adı, kod ile ara..." className="w-full h-14 bg-white border-2 border-slate-300 rounded-lg pl-4 pr-4 text-xl focus:outline-none focus:ring-2 focus:ring-pink-500"/>
                  {searchResultGroups.length > 0 && (
                      <div ref={searchResultsRef} className="absolute top-full mt-2 w-full bg-white border rounded-lg shadow-lg z-20 max-h-80 overflow-y-auto">
