                              const hasVariants = group.length > 1;
                              const isExpanded = expandedSearchResult === mainProduct.anaStokKodu;
                              const isGroupHighlighted = highlightedIndex >= 0 && navigableItems[highlightedIndex]?.type === 'group' && navigableItems[highlightedIndex]?.product.barcode === mainProduct.barcode;
                              return (
                                  <div key={mainProduct.anaStokKodu} className="border-b last:border-b-0">
                                      <div onClick={() => hasVariants ? setExpandedSearchResult(p => p === mainProduct.anaStokKodu ? null : mainProduct.anaStokKodu) : handleSearchSelect(mainProduct)} className={`p-3 hover:bg-cyan-50 flex justify-between items-center cursor-pointer ${isGroupHighlighted ? 'bg-cyan-100 search-item-highlighted' : ''}`}>
                                          <div><p className="font-semibold">{mainProduct.name.replace(/\s*\(.+\)$/, '')} - {mainProduct.marka}</p><p className="text-sm text-slate-500">{hasVariants ? `${group.length} varyasyon` : `${mainProduct.renk} - ${mainProduct.beden}`}</p></div>
                                          {hasVariants && <Icon name="arrows-vertical" className={`w-5 h-5 text-slate-400 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />}
                                      </div>
                                      {isExpanded && (
                                          <div className="bg-slate-50 p-2">{group.map(v => {
                                              const isVariantHighlighted = highlightedIndex >= 0 && navigableItems[highlightedIndex]?.type === 'variant' && navigableItems[highlightedIndex]?.product.barcode === v.barcode;
                                              return (<div key={v.barcode} onClick={() => handleSearchSelect(v)} className={`flex justify-between p-2 rounded-md hover:bg-cyan-100 cursor-pointer ${isVariantHighlighted ? 'bg-cyan-100 search-item-highlighted' : ''}`}>
