                </div>
                {selectedSupplier?.discountRate && (
                  <button onClick={handleToggleDiscount} className={`h-14 flex items-center gap-2 px-4 rounded-lg font-semibold transition ${isDiscountApplied ? 'bg-pink-600 text-white' : 'bg-white border-2 border-pink-500 text-pink-600 hover:bg-pink-50'}`}>
                      <Icon name="tag" className="w-5 h-5"/>
