                )}
              </div>
          </div>
          {error && <p className="text-red-600 mt-2 text-center text-sm animate-pulse">{error}</p>}
        </header>
        <div className="flex-grow overflow-y-auto">
          <table className="w-full text-xs text-left table-fixed">
            <thead className="text-[11px] text-amber-800 uppercase bg-amber-100 sticky top-0 z-10 select-none">
              <tr className="border-b-2 border-slate-200">
                {visibleColumns.map((col: { id: string; label: string; minWidth: number; align?: 'left' | 'right' | 'center' }) => (
                    <th 
                      key={col.id} 
                      scope="col" 
                      className={`px-4 py-2 font-bold relative group border-r border-slate-200 last:border-r-0 cursor-move ${draggedColumn.current === col.id ? 'opacity-30' : ''} ${dragOverColumn === col.id && draggedColumn.current !== col.id ? 'drag-over-indicator' : ''}`}
                      style={{ width: `${columnWidths[col.id]}px` }}
                      draggable
                      onDragStart={(e) => handleDragStart(e, col.id)}
                      onDragOver={handleDragOver}
                      onDrop={(e) => handleDrop(e, col.id)}
                      onDragEnd={handleDragEnd}
                      onDragEnter={(e) => handleDragEnter(e, col.id)}
                    >
                        <div className="flex items-center justify-between">
                          <span style={{textAlign: col.align || 'left', width: '100%'}}>{col.label}</span>
                          {col.id !== 'actions' && <Icon name="arrows-vertical" className="w-3 h-3 ml-1 text-slate-400 shrink-0" />}
                        </div>
                        {col.id !== 'actions' && 
                          <div 
                            onMouseDown={(e) => handleMouseDown(e, col.id)} 
                            className="absolute top-0 right-[-4px] h-full w-2 cursor-col-resize z-20 group-hover:bg-cyan-300/50 transition-colors"
                          />
                        }
                    </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {currentPurchase.length === 0 ? (
                <tr><td colSpan={visibleColumns.length} className="text-center py-10"><div className="flex flex-col items-center justify-center text-slate-400 p-8"><Icon name="purchase" className="w-16 h-16 mx-auto mb-4 text-slate-300"/><h3 className="text-xl font-medium text-slate-500">Fatura Boş</h3><p className="text-sm">Başlamak için bir ürünün barkodunu okutun veya arayın.</p></div></td></tr>
              ) : (currentPurchase.map((item: PurchaseItem) => (
                  <tr key={item.barcode} className="bg-white border-b last:border-0 hover:bg-amber-50 group/row">
                     {visibleColumns.map((col: { id: string; label: string; minWidth: number; align?: 'left' | 'right' | 'center' }) => {
                        let content: React.ReactNode;
                        if (col.id === 'quantity') {
                            content = (
                                <div className="flex items-center justify-center gap-2">
                                  <button onClick={() => updateQuantity(item.barcode, -1)} className="btn-quantity"><Icon name="minus" className="w-4 h-4" /></button>
                                  <span className="w-8 text-center font-bold text-md text-slate-800">{item.quantity}</span>
                                  <button onClick={() => updateQuantity(item.barcode, 1)} className="btn-quantity"><Icon name="plus" className="w-4 h-4" /></button>
                                </div>
                            );
                        } else if (col.id === 'buyPrice') {
                            content = editingBuyPrice?.barcode === item.barcode ? 
                                (<input type="text" value={editingBuyPrice.value} onChange={(e) => setEditingBuyPrice({ ...editingBuyPrice, value: e.target.value })} onBlur={handleBuyPriceUpdate} onKeyDown={(e) => handlePriceInputKeyDown(e, item.barcode)} autoFocus onFocus={(e) => e.target.select()} className="w-24 text-right bg-white border-2 border-cyan-500 rounded px-2 py-1 outline-none ring-2 ring-cyan-200"/>) : 
                                (<div onClick={() => setEditingBuyPrice({ barcode: item.barcode, value: item.buyPrice.toString() })} className="cursor-pointer p-1 -m-1 rounded hover:bg-cyan-100 flex items-center justify-end" title="Fiyatı düzenle"><span>{`${item.buyPrice.toFixed(2)} ₺`}</span><Icon name="edit" className="w-3 h-3 ml-2 text-slate-400 opacity-0 group-hover/row:opacity-100 transition-opacity" /></div>);
                        } else if (col.id === 'total') {
                            content = `${(item.buyPrice * item.quantity).toFixed(2)} ₺`;
                        } else if (col.id === 'stock') {
                            content = item.stock + item.quantity;
                        } else if (col.id === 'actions') {
                            content = <div className="flex justify-center"><button onClick={() => removeItem(item.barcode)} className="p-2 rounded-full text-slate-400 hover:bg-red-100 hover:text-red-600 transition"><Icon name="trash" className="w-4 h-4" /></button></div>
                        } else {
                            content = (item as any)[col.id] ?? '';
                        }

                        return (
                            <td key={col.id} className="px-4 py-1.5 border-r border-slate-200 last:border-r-0" style={{ textAlign: col.align || 'left', fontWeight: ['total', 'buyPrice', 'stock'].includes(col.id) ? 600 : 400, color: col.id === 'total' ? '#0891b2' : ''}}>
                                {content}
                            </td>
                        )
                    })}
                  </tr>)))}
            </tbody>
          </table>
        </div>
      </div>
      <div className="flex-shrink-0 bg-gradient-to-r from-slate-700 to-slate-800 text-white rounded-lg shadow-2xl p-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
            <div>
                <p className="text-lg font-medium text-slate-300">Toplam Ürün Adedi</p>
                <p className="text-5xl font-bold tracking-tight text-white">{totalItems}<span className="text-3xl ml-2">adet</span></p>
            </div>
            <div className="h-16 w-px bg-slate-600"></div>
            {isDiscountApplied && selectedSupplier?.discountRate && discountAmount > 0.005 && (
              <>
                <div>
                    <p className="text-lg font-medium text-slate-300">Uygulanan İskonto (%{selectedSupplier.discountRate})</p>
                    <p className="text-5xl font-bold tracking-tight text-pink-300">{discountAmount.toFixed(2)}<span className="text-3xl ml-1">₺</span></p>
                </div>
                <div className="h-16 w-px bg-slate-600"></div>
              </>
            )}
            <div>
                <p className="text-lg font-medium text-slate-300">Fatura Toplamı</p>
                <p className="text-5xl font-bold tracking-tight text-cyan-300">{total.toFixed(2)}<span className="text-3xl ml-1">₺</span></p>
            </div>
        </div>
        <div className="flex items-center gap-3"><button onClick={cancelPurchase} disabled={currentPurchase.length === 0} className="btn-footer bg-red-500/20 text-red-300 hover:bg-red-500/40">İptal Et</button><button onClick={savePurchase} disabled={currentPurchase.length === 0} className="btn-footer w-60 bg-gradient-to-r from-green-500 to-emerald-500 text-white font-bold text-xl shadow-lg hover:shadow-green-500/40 transform hover:-translate-y-1"><Icon name="check" className="w-7 h-7" /><span>Faturayı Kaydet</span></button></div>
      </div>
      <style>{`
          .btn-quantity { display: flex; align-items: center; justify-content: center; width: 1.75rem; height: 1.75rem; border-radius: 0.375rem; background-color: #e2e8f0; color: #334155; transition: all 0.2s; }
          .btn-quantity:hover { background-color: #94a3b8; color: #f8fafc; }
          .btn-footer { display: flex; align-items: center; justify-content: center; gap: 0.75rem; font-semibold; padding: 0.75rem 1.25rem; border-radius: 0.5rem; transition: all 0.2s; }
          .btn-footer:disabled { background: #475569; color: #94a3b8; cursor: not-allowed; box-shadow: none; transform: none; }
      `}</style>
    </div>
  );
};

export default PurchaseView;

import React from 'react';
import { View, AITask, TabIcon, User, CompanyInfo, Tab } from '../types';
import Header from './Header';
import Icon from './Icon';
import Clock from './Clock';
import AiTaskRunner from './AiTaskRunner';

interface NavbarProps {
  onNavigate: (view: View, label: string, icon: TabIcon, payload?: any) => void;
  aiTasks: AITask[];
  onReviewAiTask: (taskId: string) => void;
  onDismissAiTask: (taskId: string) => void;
  currentUser: User;
  onLogout: () => void;
  companyInfo: CompanyInfo;
  openTabs: Tab[];
  activeTabId: View;
  onTabClick: (view: View) => void;
  onCloseTab: (view: View) => void;
}

const NavButton: React.FC<{ onClick: () => void; icon: TabIcon; label: string; colorClasses: string; }> = ({ onClick, icon, label, colorClasses }) => (
    <button
        onClick={onClick}
        className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-semibold transition-colors ${colorClasses}`}
    >
        <Icon name={icon} className="w-5 h-5" />
        <span>{label}</span>
    </button>
);


const Navbar: React.FC<NavbarProps> = ({ onNavigate, aiTasks, onReviewAiTask, onDismissAiTask, currentUser, onLogout, companyInfo, openTabs, activeTabId, onTabClick, onCloseTab }) => {
  return (
    <header className="w-full bg-white/70 backdrop-blur-lg border-b border-slate-200/80 px-4 flex items-center justify-between shadow-sm flex-shrink-0 z-20">
      <div className="flex items-end gap-4">
        <div className="flex items-center gap-4 py-2">
            <Header companyName={companyInfo.name} />
            <div className="h-8 w-px bg-slate-300"></div>
            <div className="flex items-center gap-2">
                <NavButton 
                    onClick={() => onNavigate(View.RETURN, 'İade Ekranı', 'back')} 
                    icon="back"
                    label="İade Ekranı"
                    colorClasses="text-red-700 hover:bg-red-100/80"
                />
            </div>
        </div>

        <div className="h-6 w-px bg-slate-200 self-center"></div>

        <div className="flex items-end gap-1">
          {openTabs.map(tab => {
            const isActive = tab.id === activeTabId;
            return (
              <div
                key={tab.id}
                onClick={() => onTabClick(tab.id)}
                className={`flex items-center gap-2 pl-3 pr-2 py-2 rounded-t-md text-sm font-semibold transition-colors relative border-x border-t cursor-pointer ${
                  isActive
                    ? `bg-slate-100 border-slate-200/80 text-slate-800 -mb-[1px] border-b border-b-slate-100` // Overlap effect
                    : `bg-slate-200/60 border-transparent text-slate-600 hover:bg-slate-200`
                }`}
              >
                <Icon name={tab.icon} className={`w-4 h-4 ${isActive ? 'text-cyan-600' : 'text-slate-500'}`} />
                <span>{tab.label}</span>
                {tab.id !== View.DASHBOARD && (
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onCloseTab(tab.id);
                    }}
                    className="ml-1 p-1 rounded-full text-slate-400 hover:bg-red-200 hover:text-red-700 transition-colors"
                    title={`${tab.label} sekmesini kapat`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </div>
      <div className="flex items-center gap-3 py-2">
        <AiTaskRunner 
            tasks={aiTasks}
            onReview={onReviewAiTask}
            onDismiss={onDismissAiTask}
        />
        <Clock />
        <div className="h-8 w-px bg-slate-300"></div>
        <div className="bg-cyan-100 border border-cyan-200 rounded-lg p-1.5 px-2 flex items-center gap-2">
          <div className="text-right">
            <p className="font-semibold text-sm text-cyan-800">{currentUser.name}</p>
            <p className="text-xs text-cyan-600">{currentUser.email}</p>
          </div>
          <button onClick={onLogout} title="Çıkış Yap" className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-cyan-200/70 transition">
            <Icon name="logout" className="w-5 h-5 text-cyan-700" />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Navbar;

